import{_ as a,o as i,c as e,a2 as _}from"./chunks/framework.B72_uj9U.js";const c=JSON.parse('{"title":"供应商行为准则（模板）","description":"","frontmatter":{},"headers":[],"relativePath":"zh/templates/supplier-code.md","filePath":"zh/templates/supplier-code.md"}'),t={name:"zh/templates/supplier-code.md"};function r(o,l,n,h,s,u){return i(),e("div",null,[...l[0]||(l[0]=[_(`<h1 id="供应商行为准则-模板" tabindex="-1">供应商行为准则（模板） <a class="header-anchor" href="#供应商行为准则-模板" aria-label="Permalink to &quot;供应商行为准则（模板）&quot;">​</a></h1><blockquote><p><strong>文件属性</strong> 文件编号：SCoC-[版本号] | 版本日期：[YYYY-MM-DD] | 发布方：[采购方公司全称] | 审阅周期：每两年一次</p></blockquote><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>[采购方公司全称]（下称&quot;本公司&quot;）致力于在全球供应链中推行负责任的商业行为。本行为准则（下称&quot;准则&quot;）规定了本公司对所有供应商、分包商、代理商及其他业务合作伙伴（下统称&quot;供应商&quot;）在劳工权利、环境管理、商业道德、信息安全、知识产权及原材料溯源方面的最低行为要求。</p><p>遵守本准则是与本公司建立和维持业务关系的前提条件。本公司保留对供应商开展审核、要求提供证明文件及在发现严重违规时终止合作关系的权利。</p><p>本准则所设定的是<strong>最低要求</strong>。本公司鼓励供应商在本准则基础上追求更高标准，并将在供应商绩效评估中对持续改进给予积极认可。</p><hr><h2 id="第一章-劳工权利与工作条件" tabindex="-1">第一章　劳工权利与工作条件 <a class="header-anchor" href="#第一章-劳工权利与工作条件" aria-label="Permalink to &quot;第一章　劳工权利与工作条件&quot;">​</a></h2><h3 id="_1-1-禁止使用童工" tabindex="-1">1.1　禁止使用童工 <a class="header-anchor" href="#_1-1-禁止使用童工" aria-label="Permalink to &quot;1.1　禁止使用童工&quot;">​</a></h3><p>供应商不得雇用年龄低于当地法定最低就业年龄或低于15周岁（两者取较高者）的人员从事任何工作。对于年满15周岁但未达18周岁的未成年工，供应商须：</p><ul><li>不得安排从事夜班、危险性工作或法律禁止的岗位</li><li>定期进行健康检查（频率不低于每年一次）</li><li>建立未成年工专项登记台账</li><li>核查并留存年龄证明文件</li></ul><h3 id="_1-2-禁止强迫劳动与现代奴役" tabindex="-1">1.2　禁止强迫劳动与现代奴役 <a class="header-anchor" href="#_1-2-禁止强迫劳动与现代奴役" aria-label="Permalink to &quot;1.2　禁止强迫劳动与现代奴役&quot;">​</a></h3><p>供应商不得使用任何形式的强迫劳动、强制劳动、债务性劳动、监狱劳动或人口贩卖受害者劳动。具体包括：</p><ul><li><strong>禁止</strong>扣押员工证件（护照、身份证、居住证等）</li><li><strong>禁止</strong>向员工收取招聘费、培训费、押金或工具费用</li><li><strong>禁止</strong>以债务偿还形式约束员工不得离职</li><li>员工必须享有<strong>自愿离职</strong>的权利，离职通知期不得超过当地法律规定</li></ul><p>供应商应对其使用的劳务派遣机构进行尽职调查，确保派遣工的招募和管理不存在强迫劳动风险。</p><h3 id="_1-3-工作时间" tabindex="-1">1.3　工作时间 <a class="header-anchor" href="#_1-3-工作时间" aria-label="Permalink to &quot;1.3　工作时间&quot;">​</a></h3><ul><li>正常工作时间不得超过当地法律规定（中国《劳动法》：每日不超过8小时，每周不超过44小时）</li><li>加班须以<strong>自愿为原则</strong>，月加班时间不得超过36小时（中国法律规定）或当地法律规定的上限</li><li>每周须至少保证1天休息日</li><li>在特殊情形下（旺季、赶单）若需超出上限，须提前向员工说明并获得书面同意，同时按规定支付加班报酬</li></ul><h3 id="_1-4-薪资与福利" tabindex="-1">1.4　薪资与福利 <a class="header-anchor" href="#_1-4-薪资与福利" aria-label="Permalink to &quot;1.4　薪资与福利&quot;">​</a></h3><ul><li>薪资不得低于当地法定最低工资标准或行业协议工资标准（两者取较高者）</li><li>加班薪资须按法定比例计算（中国法律：工作日加班150%，休息日200%，法定节假日300%）</li><li>禁止任何形式的非法克扣工资（罚款除外须有书面规章制度依据）</li><li>工资须以货币形式支付，不得以实物代替</li><li>向员工提供书面工资单，清晰列明基本工资、加班费、补贴和扣款项目</li><li>按法律规定缴纳社会保险（养老、医疗、工伤、失业、生育）</li></ul><h3 id="_1-5-禁止歧视与骚扰" tabindex="-1">1.5　禁止歧视与骚扰 <a class="header-anchor" href="#_1-5-禁止歧视与骚扰" aria-label="Permalink to &quot;1.5　禁止歧视与骚扰&quot;">​</a></h3><p>供应商须建立平等就业环境，禁止基于性别、年龄、宗教、种族、民族、国籍、残疾状况、婚姻状况、怀孕状况、政治立场或性取向进行歧视。</p><ul><li>招募、晋升、薪酬、培训及解雇决定均须基于客观标准</li><li>禁止一切形式的职场暴力、骚扰、恐吓和辱骂</li><li>须建立员工申诉机制，保护申诉员工免受打击报复</li><li>依据ILO C190公约，对职场性骚扰须有明确的预防和处理程序</li></ul><h3 id="_1-6-结社自由与集体谈判" tabindex="-1">1.6　结社自由与集体谈判 <a class="header-anchor" href="#_1-6-结社自由与集体谈判" aria-label="Permalink to &quot;1.6　结社自由与集体谈判&quot;">​</a></h3><ul><li>尊重员工依法组建或参加工会及员工代表机构的权利</li><li>禁止以恐吓、威胁或不当手段阻止员工行使结社权利</li><li>在法律允许结社的司法管辖区，须诚信参与集体谈判</li><li>在结社受限的地区（如部分中国境内情形），供应商须建立替代性的工人意见表达渠道</li></ul><h3 id="_1-7-职业健康与安全" tabindex="-1">1.7　职业健康与安全 <a class="header-anchor" href="#_1-7-职业健康与安全" aria-label="Permalink to &quot;1.7　职业健康与安全&quot;">​</a></h3><ul><li>提供安全、卫生的工作环境，满足当地法律法规和客户的相关要求</li><li>识别并管理作业场所的安全风险（机械安全、化学品、高温高压、电气安全等）</li><li>提供必要的个人防护用品（PPE），并培训员工正确使用</li><li>消防安全：确保紧急疏散通道畅通、消防设备有效，员工接受消防演练</li><li>建立工伤事故报告和调查机制</li><li>若提供宿舍，须符合安全、卫生和基本生活标准；宿舍门禁不得在非紧急情况下从外部上锁</li></ul><hr><h2 id="第二章-环境合规" tabindex="-1">第二章　环境合规 <a class="header-anchor" href="#第二章-环境合规" aria-label="Permalink to &quot;第二章　环境合规&quot;">​</a></h2><h3 id="_2-1-许可证合规" tabindex="-1">2.1　许可证合规 <a class="header-anchor" href="#_2-1-许可证合规" aria-label="Permalink to &quot;2.1　许可证合规&quot;">​</a></h3><p>供应商须持有当地法律要求的全部有效环境许可证和批准（包括但不限于排污许可证、危险废物处置许可证、化学品安全生产许可证），并在许可证有效期内合规经营。</p><h3 id="_2-2-废弃物管理" tabindex="-1">2.2　废弃物管理 <a class="header-anchor" href="#_2-2-废弃物管理" aria-label="Permalink to &quot;2.2　废弃物管理&quot;">​</a></h3><ul><li>对固体废弃物、危险废物进行分类、标记和合法处置</li><li>危险废物须委托有资质的第三方处置机构，并保留转移联单</li><li>禁止非法倾倒或未经处理排放废弃物</li></ul><h3 id="_2-3-水资源与排放管理" tabindex="-1">2.3　水资源与排放管理 <a class="header-anchor" href="#_2-3-水资源与排放管理" aria-label="Permalink to &quot;2.3　水资源与排放管理&quot;">​</a></h3><ul><li>废水须经处理达标后方可排放，并保留排放监测记录</li><li>大气排放须符合当地环保标准，定期进行检测</li><li>鼓励实施节水措施，按年度向本公司披露用水量数据</li></ul><h3 id="_2-4-危险物质管理" tabindex="-1">2.4　危险物质管理 <a class="header-anchor" href="#_2-4-危险物质管理" aria-label="Permalink to &quot;2.4　危险物质管理&quot;">​</a></h3><ul><li>对化学品建立清单和安全数据表（SDS）管理体系</li><li>遵守RoHS、REACH等适用的物质限制法规，禁止在产品中使用本公司限制物质清单所列物质</li><li>化学品的储存、使用和处置须有防泄漏措施</li></ul><h3 id="_2-5-气候与能源" tabindex="-1">2.5　气候与能源 <a class="header-anchor" href="#_2-5-气候与能源" aria-label="Permalink to &quot;2.5　气候与能源&quot;">​</a></h3><ul><li>按本公司要求，定期披露温室气体排放数据（Scope 1、Scope 2；战略供应商须包含Scope 3估算）</li><li>参与本公司的碳减排项目和目标设定</li><li>积极推进可再生能源使用，制定能源管理计划</li></ul><h3 id="_2-6-生物多样性保护与土地利用" tabindex="-1">2.6　生物多样性保护与土地利用 <a class="header-anchor" href="#_2-6-生物多样性保护与土地利用" aria-label="Permalink to &quot;2.6　生物多样性保护与土地利用&quot;">​</a></h3><p>生物多样性损失是与气候变化同等重要的全球性风险，供应商须采取以下措施：</p><p><strong>选址与风险筛查：</strong></p><ul><li>新建或扩建设施前，须核查场地是否位于或毗邻以下区域： <ul><li>关键生物多样性区域（KBA）：通过 <a href="https://www.keybiodiversityareas.org" target="_blank" rel="noreferrer">keybiodiversityareas.org</a> 核查全球KBA数据库</li><li>世界自然遗产地或其缓冲区（UNESCO World Heritage）</li><li>国家/地方级自然保护区、生态保护红线（中国）</li><li>拉姆萨尔湿地（Ramsar Wetlands）</li><li>IUCN濒危物种的重要栖息地</li></ul></li><li>位于或毗邻上述区域的供应商，须提供经独立第三方验证的生物多样性影响评估（依据IFC绩效标准6，PS6）</li></ul><p><strong>无净损失原则（No Net Loss）：</strong></p><ul><li>供应商运营须遵循缓解层级（Mitigation Hierarchy）：<strong>回避 → 最小化 → 修复 → 补偿</strong></li><li>在关键栖息地内，须实现生物多样性净增益（Net Gain）而非仅无净损失</li><li>禁止在IFC PS6定义的&quot;关键栖息地&quot;中开展新的生产活动，除非可证明没有其他选址替代方案，并已落实净增益措施</li></ul><p><strong>反毁林：</strong></p><ul><li>供应商采购的农业原材料（大豆、棕榈油、可可、咖啡、牛肉/皮革、木材、橡胶）须符合《欧盟毁林法规》（EUDR）要求，可提供农场级别的地理坐标（GPS多边形）和土地合法性证明</li><li>禁止采购来自2020年12月31日后毁林土地上生产的原材料</li></ul><p><strong>披露：</strong></p><ul><li>战略供应商须按照TNFD（自然相关财务信息披露框架）LEAP方法论，识别其运营对生物多样性的依赖与影响，并向本公司年度报告重大自然相关风险</li></ul><h3 id="_2-7-社区福祉与利益相关方权利" tabindex="-1">2.7　社区福祉与利益相关方权利 <a class="header-anchor" href="#_2-7-社区福祉与利益相关方权利" aria-label="Permalink to &quot;2.7　社区福祉与利益相关方权利&quot;">​</a></h3><p>供应商的运营不应对周边社区产生不当的负面影响：</p><p><strong>社区影响管控：</strong></p><ul><li>对可能影响周边居民的噪声、粉尘、气味、光污染、交通等问题，须建立监测机制和邻居投诉渠道</li><li>废水排放、固废处置、危险品储运的位置须远离居民区和社区水源，或采取有效隔离措施</li><li>须建立<strong>对外社区申诉机制</strong>（独立于员工内部投诉渠道），允许受影响的社区成员提出关切，并在合理期限内给予回复</li></ul><p><strong>原住民与当地社区权利（适用时）：</strong></p><ul><li>凡涉及可能影响原住民或传统社区土地、资源或生计的项目（新建设施、采矿、农业开发、水坝等），须遵循**自由事先知情同意（FPIC）**原则： <ul><li>须在项目决策前（Free and Prior）与相关社区进行真实协商</li><li>须以社区可理解的语言提供完整信息（Informed）</li><li>须取得社区集体同意（Consent），而非单方面告知</li></ul></li><li>禁止在未完成FPIC程序的情况下推进可能影响原住民权利的项目</li><li>如项目涉及非自愿搬迁（Involuntary Resettlement），须参照IFC绩效标准5（PS5）制定搬迁行动计划</li></ul><p><strong>社区投资：</strong></p><ul><li>鼓励供应商设立与社区共享的利益分享机制（如优先雇用当地居民、支持当地基础设施、参与社区发展项目），并对相关活动进行年度记录和披露</li></ul><h3 id="_2-8-动物福利-适用于相关行业" tabindex="-1">2.8　动物福利（适用于相关行业） <a class="header-anchor" href="#_2-8-动物福利-适用于相关行业" aria-label="Permalink to &quot;2.8　动物福利（适用于相关行业）&quot;">​</a></h3><p>本条款适用于在供应链中涉及活体动物的供应商，包括但不限于：食品与农业（畜牧、水产、乳制品、蛋类）、制药（动物实验）、化妆品（动物测试）、服装（皮革、羊毛、羽绒、蚕丝）及宠物用品。</p><p><strong>五大自由原则（Five Freedoms，Brambell框架）：</strong> 所有受管控动物须享有：</p><ol><li><strong>免于饥渴的自由</strong> — 随时获得清洁饮水和营养适当的饲料</li><li><strong>免于不适的自由</strong> — 提供适当的栖息环境，含遮蔽和舒适休息区</li><li><strong>免于疼痛、伤害和疾病的自由</strong> — 预防措施和及时的兽医救治</li><li><strong>表达正常行为的自由</strong> — 提供足够空间、设施和同类群体</li><li><strong>免于恐惧和痛苦的自由</strong> — 确保动物免受精神创伤</li></ol><p><strong>具体禁止行为：</strong></p><ul><li>禁止使用妊娠笼（gestation crates）、蛋鸡笼养（battery cages）等严重限制动物基本行为的密集饲养方式</li><li>禁止强制填饲（force-feeding）以生产鹅肝/鸭肝（foie gras）</li><li>禁止在未施用适当止痛措施的情况下进行割耳、去角、剪喙、断尾等疼痛性处置（mulesing须使用止痛剂）</li><li>禁止使用欧盟已禁止的动物实验方法进行化妆品安全测试</li><li>禁止将抗生素用作促生长添加剂（仅限治疗目的使用）</li></ul><p><strong>屠宰与运输：</strong></p><ul><li>屠宰前须对动物实施有效的人道致晕（stunning），符合OIE（世界动物卫生组织）标准</li><li>活体动物运输须遵守最大运输时长限制，提供适当的通风、水和空间密度</li><li>禁止在未获批准条件下跨境运输活体动物</li></ul><p><strong>认证参照：</strong> 供应商可通过以下认证证明动物福利合规，本公司将在供应商评估中予以认可：</p><ul><li>RSPCA Assured（英国）</li><li>Global Animal Partnership（GAP，美国）</li><li>Certified Humane（美国）</li><li>有机认证（EC 834/2007，含动物福利标准）</li><li>ASC（水产养殖管理委员会）</li></ul><hr><h2 id="第三章-商业道德" tabindex="-1">第三章　商业道德 <a class="header-anchor" href="#第三章-商业道德" aria-label="Permalink to &quot;第三章　商业道德&quot;">​</a></h2><h3 id="_3-1-反贿赂与反腐败" tabindex="-1">3.1　反贿赂与反腐败 <a class="header-anchor" href="#_3-1-反贿赂与反腐败" aria-label="Permalink to &quot;3.1　反贿赂与反腐败&quot;">​</a></h3><p>供应商须遵守所有适用的反贿赂和反腐败法律，包括但不限于中国《反不正当竞争法》、英国《贿赂法案》（UKBA）、美国《反海外腐败法》（FCPA）以及经营所在地的相关法律。</p><ul><li><strong>禁止</strong>直接或间接向任何人（包括政府官员、国有企业员工及私营部门人员）提供、承诺或给予金钱、礼品或其他有价物品，以换取不正当商业利益</li><li><strong>禁止</strong>接受可能影响商业判断的任何形式的好处</li><li>供应商须建立与其业务规模和风险相称的反腐败管理体系，包括书面政策、员工培训和监督机制</li></ul><h3 id="_3-2-礼品与商务招待" tabindex="-1">3.2　礼品与商务招待 <a class="header-anchor" href="#_3-2-礼品与商务招待" aria-label="Permalink to &quot;3.2　礼品与商务招待&quot;">​</a></h3><ul><li>礼品与招待的给予和接受须符合正常商务惯例，价值须合理</li><li>禁止向正在进行商业谈判或许可证申请的对方人员提供礼品或招待</li><li>禁止以现金、礼品卡、购物券、贵金属等现金等价物形式给予礼品</li><li>建立礼品台账，记录超过[供应商内部阈值，如500元人民币/次]的礼品和招待</li></ul><h3 id="_3-3-利益冲突" tabindex="-1">3.3　利益冲突 <a class="header-anchor" href="#_3-3-利益冲突" aria-label="Permalink to &quot;3.3　利益冲突&quot;">​</a></h3><ul><li>要求员工主动申报与本公司员工之间可能影响公正商业判断的个人关系或财务利益</li><li>建立利益冲突申报制度，相关人员须在入职时、每年及情形发生变化时进行申报</li><li>存在利益冲突的人员须从相关决策中回避</li></ul><h3 id="_3-4-制裁合规与出口管制" tabindex="-1">3.4　制裁合规与出口管制 <a class="header-anchor" href="#_3-4-制裁合规与出口管制" aria-label="Permalink to &quot;3.4　制裁合规与出口管制&quot;">​</a></h3><ul><li>对本公司员工、供应商及其股东进行制裁名单筛查，包括OFAC SDN名单、欧盟综合制裁名单、联合国制裁名单及中国相关名单</li><li>不得与受制裁方进行任何直接或间接业务往来</li><li>遵守适用的出口管制法律（包括美国EAR/ITAR、中国《出口管制法》）</li><li>禁止在明知可能被用于违禁用途的情况下转售或转移受管制物项</li></ul><h3 id="_3-5-竞争法与反垄断" tabindex="-1">3.5　竞争法与反垄断 <a class="header-anchor" href="#_3-5-竞争法与反垄断" aria-label="Permalink to &quot;3.5　竞争法与反垄断&quot;">​</a></h3><ul><li>不得参与价格固定、市场分割、串通投标等违反竞争法的行为</li><li>在与竞争对手的接触中，避免交换敏感的竞争性信息</li></ul><hr><h2 id="第四章-信息安全与数据保护" tabindex="-1">第四章　信息安全与数据保护 <a class="header-anchor" href="#第四章-信息安全与数据保护" aria-label="Permalink to &quot;第四章　信息安全与数据保护&quot;">​</a></h2><h3 id="_4-1-保密义务" tabindex="-1">4.1　保密义务 <a class="header-anchor" href="#_4-1-保密义务" aria-label="Permalink to &quot;4.1　保密义务&quot;">​</a></h3><ul><li>对本公司提供的所有技术文件、商业信息、合同内容及供应商关系信息严格保密</li><li>保密义务在合同终止后仍持续有效（期限不少于[5年]或信息进入公共领域为止）</li><li>接触保密信息的员工须签署书面保密承诺</li></ul><h3 id="_4-2-网络安全基线要求" tabindex="-1">4.2　网络安全基线要求 <a class="header-anchor" href="#_4-2-网络安全基线要求" aria-label="Permalink to &quot;4.2　网络安全基线要求&quot;">​</a></h3><p>战略供应商（有权访问本公司系统或处理本公司数据者）须满足：</p><ul><li>部署防病毒/反恶意软件，定期更新</li><li>对关键系统实施访问控制（最小权限原则、多因素认证）</li><li>定期对操作系统和应用程序进行安全补丁更新</li><li>对敏感数据进行加密传输和存储</li><li>建立安全事件报告机制：如发现可能影响本公司数据或系统的安全事件，须在<strong>24小时内</strong>通知本公司</li></ul><h3 id="_4-3-数据保护" tabindex="-1">4.3　数据保护 <a class="header-anchor" href="#_4-3-数据保护" aria-label="Permalink to &quot;4.3　数据保护&quot;">​</a></h3><ul><li>对本公司提供的个人数据（员工、客户、消费者等）须按适用数据保护法律（包括中国PIPL、欧盟GDPR等）处理</li><li>不得将本公司的个人数据用于合同范围以外的用途</li><li>合同终止后须按约定方式删除或返还个人数据</li></ul><hr><h2 id="第五章-知识产权" tabindex="-1">第五章　知识产权 <a class="header-anchor" href="#第五章-知识产权" aria-label="Permalink to &quot;第五章　知识产权&quot;">​</a></h2><h3 id="_5-1-尊重本公司知识产权" tabindex="-1">5.1　尊重本公司知识产权 <a class="header-anchor" href="#_5-1-尊重本公司知识产权" aria-label="Permalink to &quot;5.1　尊重本公司知识产权&quot;">​</a></h3><ul><li>本公司提供的设计、图纸、工艺参数、商标、技术文件等知识产权归本公司所有</li><li>仅可将上述信息用于履行本合同的目的，不得用于生产标外（未授权）产品</li><li>合同终止后须销毁或返还所有含有本公司技术信息的载体，并提供书面确认</li></ul><h3 id="_5-2-不侵犯第三方知识产权" tabindex="-1">5.2　不侵犯第三方知识产权 <a class="header-anchor" href="#_5-2-不侵犯第三方知识产权" aria-label="Permalink to &quot;5.2　不侵犯第三方知识产权&quot;">​</a></h3><ul><li>所提供产品和服务不得侵犯任何第三方的专利、商标、版权、商业秘密等知识产权</li><li>如使用第三方技术或开源软件，须确保获得了适当的授权并遵守相关许可证条款</li><li>如收到第三方知识产权侵权指控，须立即通知本公司</li></ul><h3 id="_5-3-防伪与产品真实性" tabindex="-1">5.3　防伪与产品真实性 <a class="header-anchor" href="#_5-3-防伪与产品真实性" aria-label="Permalink to &quot;5.3　防伪与产品真实性&quot;">​</a></h3><ul><li>所使用的原材料、零部件和包装须来自经本公司认可的正规渠道</li><li>禁止在产品或包装上使用任何假冒标识</li><li>须按本公司要求实施防伪标识或追溯措施</li></ul><hr><h2 id="第六章-供应链透明度" tabindex="-1">第六章　供应链透明度 <a class="header-anchor" href="#第六章-供应链透明度" aria-label="Permalink to &quot;第六章　供应链透明度&quot;">​</a></h2><h3 id="_6-1-分包商管理" tabindex="-1">6.1　分包商管理 <a class="header-anchor" href="#_6-1-分包商管理" aria-label="Permalink to &quot;6.1　分包商管理&quot;">​</a></h3><ul><li>将生产活动（全部或重大部分）转包给第三方须提前获得本公司书面同意</li><li>经批准的分包商须满足本准则的相同要求</li><li>须对分包商进行定期评估，并向本公司披露主要分包商名单</li></ul><h3 id="_6-2-冲突矿产" tabindex="-1">6.2　冲突矿产 <a class="header-anchor" href="#_6-2-冲突矿产" aria-label="Permalink to &quot;6.2　冲突矿产&quot;">​</a></h3><p>如产品含有锡（Sn）、钽（Ta）、钨（W）、金（Au）（&quot;3TG&quot;）或钴（Co），供应商须：</p><ul><li>年度填写CMRT/COBALT报告模板</li><li>对冶炼厂/精炼厂来源进行追踪，优先使用经RMAP认证的冶炼厂</li><li>对3TG/钴来源做出无冲突矿产的书面声明</li></ul><h3 id="_6-3-禁止欺诈性原产地申报" tabindex="-1">6.3　禁止欺诈性原产地申报 <a class="header-anchor" href="#_6-3-禁止欺诈性原产地申报" aria-label="Permalink to &quot;6.3　禁止欺诈性原产地申报&quot;">​</a></h3><ul><li>对产品原产地、成分、认证状态等信息的申报须真实准确</li><li>禁止通过虚假转运、最低限度加工等手段规避原产地规则</li></ul><hr><h2 id="第七章-管理体系要求" tabindex="-1">第七章　管理体系要求 <a class="header-anchor" href="#第七章-管理体系要求" aria-label="Permalink to &quot;第七章　管理体系要求&quot;">​</a></h2><h3 id="_7-1-记录保存" tabindex="-1">7.1　记录保存 <a class="header-anchor" href="#_7-1-记录保存" aria-label="Permalink to &quot;7.1　记录保存&quot;">​</a></h3><ul><li>与本准则合规有关的记录（员工名册、工资台账、环保监测记录、培训记录等）须保存至少**[5年]**</li><li>记录须以可供审查的形式保存，并在审核时提供给本公司或本公司授权的审核方</li></ul><h3 id="_7-2-整改机制" tabindex="-1">7.2　整改机制 <a class="header-anchor" href="#_7-2-整改机制" aria-label="Permalink to &quot;7.2　整改机制&quot;">​</a></h3><ul><li>如审核或自查发现不符合本准则的情况，须制定整改行动计划（CAP）并在约定期限内完成整改</li><li>整改进度须向本公司定期报告</li></ul><h3 id="_7-3-培训与意识" tabindex="-1">7.3　培训与意识 <a class="header-anchor" href="#_7-3-培训与意识" aria-label="Permalink to &quot;7.3　培训与意识&quot;">​</a></h3><ul><li>须确保与本准则相关要求直接关联的员工（管理人员、采购、合规、生产主管等）接受相关培训</li><li>培训须覆盖与其岗位相关的具体要求，并保留培训记录</li></ul><hr><h2 id="第八章-审核权与信息获取权" tabindex="-1">第八章　审核权与信息获取权 <a class="header-anchor" href="#第八章-审核权与信息获取权" aria-label="Permalink to &quot;第八章　审核权与信息获取权&quot;">​</a></h2><p>本公司或本公司授权的第三方审核机构有权对供应商进行审核，以核实其对本准则的遵守情况。审核可采取以下形式：</p><ul><li><strong>预告审核</strong>（Announced Audit）：提前[30天]通知</li><li><strong>短期通知审核</strong>（Short-notice Audit）：提前[48-72小时]通知，适用于存在违规风险的情况</li><li><strong>不预告审核</strong>（Unannounced Audit）：针对高风险或曾发现重大违规的供应商</li></ul><p>供应商须配合审核，包括：提供相关文件和记录、允许审核员进入生产场所、允许对工人进行独立保密访谈。</p><hr><h2 id="第九章-违规处理" tabindex="-1">第九章　违规处理 <a class="header-anchor" href="#第九章-违规处理" aria-label="Permalink to &quot;第九章　违规处理&quot;">​</a></h2><p>本公司将根据违规的性质和严重程度，采取以下一项或多项措施：</p><table tabindex="0"><thead><tr><th>违规级别</th><th>典型情形</th><th>处理措施</th></tr></thead><tbody><tr><td>轻微违规</td><td>记录缺失；培训未完成；礼品台账不规范</td><td>书面通知；要求在30天内整改</td></tr><tr><td>一般违规</td><td>工时超标（&lt;10%）；环保许可证过期但正在续期；礼品政策违反但无腐败意图</td><td>书面警告；整改行动计划；90天内复查</td></tr><tr><td>重大违规</td><td>发现使用童工；强迫劳动信号；重大贿赂行为；制裁名单命中；重大数据泄露</td><td>立即暂停新订单；启动调查；要求第三方审核；视结果决定是否终止合作</td></tr><tr><td>零容忍违规</td><td>欺骗性行为（伪造审核记录、销毁证据）；人口贩卖；故意仿冒本公司产品；明知故犯的贿赂腐败</td><td>立即终止合作关系；视情况向监管机构举报</td></tr></tbody></table><hr><h2 id="第十章-签署确认" tabindex="-1">第十章　签署确认 <a class="header-anchor" href="#第十章-签署确认" aria-label="Permalink to &quot;第十章　签署确认&quot;">​</a></h2><p>以下供应商代表人阅读并理解本行为准则的全部条款，确认供应商同意遵守上述要求，并授权本公司对供应商的合规情况进行审核。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>供应商全称：_______________________________________________</span></span>
<span class="line"><span>注册地址：_______________________________________________</span></span>
<span class="line"><span>统一社会信用代码（或营业执照编号）：________________________</span></span>
<span class="line"><span>法定代表人/授权签署人姓名：________________________________</span></span>
<span class="line"><span>职务：___________________________________________________</span></span>
<span class="line"><span>签署日期：_______________________________________________</span></span>
<span class="line"><span>签名/公章：_______________________________________________</span></span></code></pre></div><hr><p><em>本准则版本：[版本号] | 发布日期：[YYYY-MM-DD] | 如有疑问，请联系：[合规部门联系方式]</em></p>`,129)])])}const p=a(t,[["render",r]]);export{c as __pageData,p as default};
